sql:
SELECT COUNT(*) 
FROM battles 
WHERE result = 'win';

SELECT wins AS total_wins
FROM statistics
WHERE pokemon_id = 1;

SELECT species, MAX(base_experience) AS max_base_experience
FROM species
GROUP BY species;

SELECT MAX(base_experience) AS max_base_experience
FROM species
WHERE is_legendary = 0 AND hidden_ability IS NOT NULL;

SELECT AVG(base_experience) AS average_base_experience, COUNT(DISTINCT id) AS number_of_legendary_species
FROM species
WHERE is_legendary = 1 AND base_experience > 100;

SELECT AVG(base_experience) AS average_base_experience
FROM species
WHERE is_legendary = 1 OR is_mythical = 1;

SELECT AVG(s.base_experience) AS average_base_experience
FROM species s
JOIN evolutions e ON s.id = e.base_species_id;

SELECT species 
FROM species 
WHERE base_experience = (SELECT MAX(base_experience) FROM species);

SELECT species
FROM species
ORDER BY base_experience DESC;

SELECT s.species, s.id AS species_id
FROM species s
INNER JOIN evolutions e ON s.id = e.base_species_id;

SELECT s.species, st.total_battles
FROM species s
JOIN statistics st ON s.id = st.pokemon_id;

external_knowledge:
- Success rate refers to the win rate calculated as wins divided by total battles;
- Victorious battles specifically mean battles where the result was a win;
- The top five indicates the ranking based on the highest values of the success rate.

- "singularly-focused Pokémon types" refers to types with only a primary type and no secondary type;
- "stood tall" metaphorically represents having a high win rate;
- "a decade's worth of battles" refers to having at least 10 battle records.
